#!/usr/bin/env python3
import os,sys,json,glob,time,subprocess,base64,urllib.request,urllib.error,re,traceback
o={"kind":"diag3","ts":int(time.time())}
def run():
    for p in ("/etc/atlas/autopull.env","/etc/atlas/db.env"):
        if os.path.exists(p):
            for ln in open(p):
                ln=ln.strip()
                if ln.startswith("export "): ln=ln[7:]
                if "=" in ln and not ln.startswith("#"):
                    k,v=ln.split("=",1); k=k.strip()
                    if k and k not in os.environ: os.environ[k]=v.strip().strip('"').strip("'")
    # source-hunter + qa + reenrich/requeue script heads
    pats=("*hunter*","*source*","*promote*","*qa*","*reenrich*","*requeue*","*ladder*","*czds*")
    files=sorted({f for pat in pats for f in glob.glob("/opt/atlas/**/"+pat+".py",recursive=True)})
    o["py_files"]=[{"p":f,"b":os.path.getsize(f)} for f in files[:40]]
    o["heads"]={}
    for f in files:
        nm=os.path.basename(f)
        if any(x in nm for x in ("hunter","promote","qa_audit","reenrich","ladder","requeue")):
            try: o["heads"][f]=open(f,encoding="utf-8",errors="replace").read()[:2600]
            except Exception as e: o["heads"][f]="ERR"+str(e)
        if len(o["heads"])>=5: break
    # systemd units (find the requeue/reenrich + hunter timers + lanes)
    try: o["units"]=subprocess.run(["bash","-lc","systemctl list-units --type=service,timer --all --no-pager 2>/dev/null | grep -iE 'atlas|reenrich|requeue|hunter|socrata|deepcrawl|ladder' | awk '{print $1,$3,$4}'"],capture_output=True,text=True).stdout[:2500]
    except Exception as e: o["units"]="ERR"+str(e)
    # autopull lanes mechanism (how lifeline/data/feature lanes drain)
    try:
        ap=open(glob.glob("/opt/atlas/**/atlas-autopull.sh",recursive=True)[0],encoding="utf-8",errors="replace").read()
        o["lanes_logic"]=("\n".join([l for l in ap.split("\n") if re.search(r'lane|LANE|queue\[|manifests/|last_seq|gh_put|409',l)]))[:2200]
    except Exception as e: o["lanes_logic"]="ERR"+str(e)
    # DB: ICP category composition + source/region dist + coverage
    try:
        sys.path.insert(0,"/opt/atlas/importers"); import socrata_import as si
        c=si.connect_pg(); cur=c.cursor()
        cur.execute("SELECT count(*) FROM atlas.business"); o["business_total"]=int(cur.fetchone()[0])
        cur.execute("SELECT count(*) FROM atlas.business WHERE website IS NOT NULL"); o["with_website"]=int(cur.fetchone()[0])
        cur.execute("SELECT count(*) FROM atlas.business WHERE email IS NOT NULL AND email<>''"); o["with_email"]=int(cur.fetchone()[0])
        try:
            cur.execute("SELECT count(*) FROM atlas.business WHERE qa_status='pass'"); o["qa_pass"]=int(cur.fetchone()[0])
        except Exception as e: o["qa_pass"]="ERR"+str(e)
        cur.execute("SELECT source,count(*) FROM atlas.business GROUP BY 1 ORDER BY 2 DESC LIMIT 30"); o["source_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
        cur.execute("SELECT region,count(*) FROM atlas.business WHERE region IS NOT NULL GROUP BY 1 ORDER BY 2 DESC LIMIT 25"); o["region_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
        try:
            cur.execute("SELECT lower(category),count(*) FROM atlas.business WHERE category IS NOT NULL GROUP BY 1 ORDER BY 2 DESC LIMIT 45"); o["category_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
        except Exception as e: o["category_dist"]="ERR"+str(e)
        # enrich_queue pending/done (for the throttle)
        try:
            cur.execute("SELECT status,count(*) FROM atlas.enrich_queue GROUP BY 1"); o["enrich_queue"]={r[0]:int(r[1]) for r in cur.fetchall()}
        except Exception as e: o["enrich_queue"]="ERR"+str(e)
        c.close()
    except Exception as e: o["db_err"]=str(e)[:300]
def put():
    tok=os.environ.get("STATUS_TOKEN");repo=os.environ.get("STATUS_REPO","cloudwalker171/atlas-manifests")
    if not tok: o["nopub"]=1; return
    url="https://api.github.com/repos/%s/contents/status/hetzner/diag3.json"%repo
    for _ in range(6):
        sha=None
        try:
            rr=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Accept":"application/vnd.github+json"})
            sha=json.load(urllib.request.urlopen(rr,timeout=20)).get("sha")
        except Exception: sha=None
        b={"message":"diag3","content":base64.b64encode(json.dumps(o,indent=1,default=str).encode()).decode(),"branch":"main"}
        if sha:b["sha"]=sha
        try:
            rq=urllib.request.Request(url,data=json.dumps(b).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Content-Type":"application/json","Accept":"application/vnd.github+json"})
            urllib.request.urlopen(rq,timeout=25); print("diag3 ok"); return
        except urllib.error.HTTPError as e:
            if e.code==409: time.sleep(1.5); continue
            print("err",e.code); return
        except Exception as e: print("err",str(e)[:80]); return
try:
    run()
except Exception as e:
    o["fatal"]=str(e)[:200]; o["trace"]=traceback.format_exc()[-1000:]
try: put()
except Exception as e: print("pub_fatal",str(e)[:120])
sys.exit(0)
